function [logTtl,logData] = fAdd2LogFile(logPath,ttl,dat)%% add data to existing logfile%% ok = fAdd2LogFile(logPath,ttl,data)%% logPath: path for existing log file% ttl: title for extra data% dat: data to be added%% Written by Kei Nakamura% 2018/4/5 ver.1: created% 2026/2/24 ver.1b: added output logTtl,logData %% main[logTtl,logData,~,~,~] = fLogReadV07(logPath);  % read lognmbDOut = numel(ttl);   % # of dataprvLog = fLogClmnFindV01(logTtl,ttl{1},1);   % see previous log existif prvLog==0    temp = cell(nmbDOut,1);    cmbTtl = [logTtl;temp,ttl'];    cmbData = [logData,arrayfun(@num2str,dat,'unif',0)];    fTxtOutV02(logPath,cmbTtl,cmbData);  else    logData(:,prvLog:prvLog+nmbDOut-1) = arrayfun(@num2str,dat,'unif',0);    fTxtOutV02(logPath,logTtl,logData); end
